SELECT id, agent_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, create_time, thinking_content
FROM chat_history
WHERE agent_id = #{agentId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, agent_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, create_time, thinking_content
FROM chat_history
WHERE agent_id = #{agentId} and tool_call_id = #{toolCallId}
limit 1;

mapper.update:
UPDATE chat_history
SET tool_call_status = #{toolCallStatus}, content = #{content}
WHERE id = #{id}
